import { recentQuoteRequestCount, saveQuoteRequest } from "@/lib/content-store";

export const dynamic = "force-dynamic";

const clean = (value: unknown, max: number) => String(value ?? "").trim().slice(0, max);

async function fingerprint(request: Request) {
  const ip = request.headers.get("cf-connecting-ip") || request.headers.get("x-forwarded-for")?.split(",")[0]?.trim() || "unknown";
  const source = `${ip}|${request.headers.get("user-agent") || ""}|${process.env.ADMIN_SESSION_SECRET || "ulucan"}`;
  const digest = await crypto.subtle.digest("SHA-256", new TextEncoder().encode(source));
  return Array.from(new Uint8Array(digest)).map((byte) => byte.toString(16).padStart(2, "0")).join("");
}

export async function POST(request: Request) {
  const origin = request.headers.get("origin");
  const host = request.headers.get("x-forwarded-host") || request.headers.get("host");
  if (origin && host && new URL(origin).host !== host) return Response.json({ error: "Geçersiz istek." }, { status: 403 });

  const body = await request.json().catch(() => ({})) as Record<string, unknown>;
  if (clean(body.website, 200)) return Response.json({ ok: true });

  const startedAt = Number(body.startedAt || 0);
  const elapsed = Date.now() - startedAt;
  if (!Number.isFinite(startedAt) || elapsed < 2500 || elapsed > 7_200_000) {
    return Response.json({ error: "Form güvenlik doğrulamasından geçemedi. Sayfayı yenileyip tekrar deneyin." }, { status: 400 });
  }

  const data = {
    name: clean(body.name, 120), company: clean(body.company, 160), phone: clean(body.phone, 40),
    email: clean(body.email, 160).toLowerCase(), projectType: clean(body.projectType, 120),
    location: clean(body.location, 180), message: clean(body.message, 3000),
  };
  if (data.name.length < 2 || data.message.length < 10 || (!data.phone && !data.email)) {
    return Response.json({ error: "Adınızı, talep detayını ve telefon veya e-posta bilginizi girin." }, { status: 400 });
  }
  if (data.email && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(data.email)) return Response.json({ error: "Geçerli bir e-posta adresi girin." }, { status: 400 });

  const requestFingerprint = await fingerprint(request);
  if (await recentQuoteRequestCount(requestFingerprint) >= 5) {
    return Response.json({ error: "Çok fazla talep gönderildi. Lütfen bir saat sonra tekrar deneyin." }, { status: 429 });
  }
  await saveQuoteRequest({ ...data, fingerprint: requestFingerprint });
  return Response.json({ ok: true });
}
